import{_ as a,o as t,c as i,a6 as n}from"./chunks/framework.tMKqR5tb.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/installation.md","filePath":"getting-started/installation.md","lastUpdated":1781558313000}'),l={name:"getting-started/installation.md"};function s(r,e,o,h,d,p){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h1><p>Download the launcher from <a href="/papyrus-client/download">Download</a>, then follow the steps for your platform.</p><h2 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to “macOS”">​</a></h2><p>Papyrus Client ships as a <strong><code>.pkg</code> installer</strong> for Apple Silicon Macs (<code>arm64</code>).</p><h3 id="_1-download-the-installer" tabindex="-1">1. Download the installer <a class="header-anchor" href="#_1-download-the-installer" aria-label="Permalink to “1. Download the installer”">​</a></h3><p>Get the latest <code>Papyrus Client-&lt;version&gt;-arm64.pkg</code> from <a href="https://github.com/codingsushi79/Papyrus-Client/releases" target="_blank" rel="noreferrer">GitHub Releases</a> or the download picker on the docs site.</p><h3 id="_2-remove-the-quarantine-flag-if-macos-blocks-the-file" tabindex="-1">2. Remove the quarantine flag (if macOS blocks the file) <a class="header-anchor" href="#_2-remove-the-quarantine-flag-if-macos-blocks-the-file" aria-label="Permalink to “2. Remove the quarantine flag (if macOS blocks the file)”">​</a></h3><p>Browsers mark downloaded files with a quarantine attribute. If macOS refuses to open the installer, run this in <strong>Terminal</strong> (replace the path with your download location):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -dr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> com.apple.quarantine</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Downloads/Papyrus</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Client-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.pkg</span></span></code></pre></div><p>Then double-click the <code>.pkg</code> again.</p><h3 id="_3-run-the-installer" tabindex="-1">3. Run the installer <a class="header-anchor" href="#_3-run-the-installer" aria-label="Permalink to “3. Run the installer”">​</a></h3><ol><li>Open the <code>.pkg</code> file</li><li>Follow the installer prompts</li><li>Papyrus Client is installed to <strong>Applications</strong></li></ol><h3 id="_4-allow-the-app-to-run-unsigned-build" tabindex="-1">4. Allow the app to run (unsigned build) <a class="header-anchor" href="#_4-allow-the-app-to-run-unsigned-build" aria-label="Permalink to “4. Allow the app to run (unsigned build)”">​</a></h3><p>Papyrus Client is not notarized yet. On first launch, macOS may say the app cannot be opened because the developer cannot be verified.</p><p><strong>Option A — Right-click open</strong></p><ol><li>Open <strong>Finder → Applications</strong></li><li>Right-click <strong>Papyrus Client</strong></li><li>Choose <strong>Open</strong></li><li>Click <strong>Open</strong> in the dialog</li></ol><p><strong>Option B — Remove quarantine from the installed app</strong></p><p>If the app still will not launch, run:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">xattr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/Applications/Papyrus Client.app&quot;</span></span></code></pre></div><p>Then open Papyrus Client from Applications or Spotlight.</p><h3 id="_5-updates" tabindex="-1">5. Updates <a class="header-anchor" href="#_5-updates" aria-label="Permalink to “5. Updates”">​</a></h3><p>The launcher checks for updates automatically. macOS updates are delivered as <code>.zip</code> files; the <code>.pkg</code> is only needed for the first install.</p><hr><h2 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to “Windows”">​</a></h2><p>Papyrus Client ships as an <strong>NSIS <code>.exe</code> installer</strong> for 64-bit Windows.</p><h3 id="_1-download-the-installer-1" tabindex="-1">1. Download the installer <a class="header-anchor" href="#_1-download-the-installer-1" aria-label="Permalink to “1. Download the installer”">​</a></h3><p>Get <code>Papyrus Client Setup &lt;version&gt;.exe</code> from <a href="https://github.com/codingsushi79/Papyrus-Client/releases" target="_blank" rel="noreferrer">GitHub Releases</a>.</p><h3 id="_2-run-the-installer" tabindex="-1">2. Run the installer <a class="header-anchor" href="#_2-run-the-installer" aria-label="Permalink to “2. Run the installer”">​</a></h3><ol><li>Double-click the <code>.exe</code></li><li>If <strong>SmartScreen</strong> appears (“Windows protected your PC”), click <strong>More info</strong>, then <strong>Run anyway</strong></li><li>Choose an install folder if prompted</li><li>Finish setup and launch from the desktop or Start menu shortcut</li></ol><p>Papyrus Client is not code-signed yet, so SmartScreen may warn on the first install. This is expected for community builds.</p><hr><h2 id="mod-only-no-launcher" tabindex="-1">Mod only (no launcher) <a class="header-anchor" href="#mod-only-no-launcher" aria-label="Permalink to “Mod only (no launcher)”">​</a></h2><p>If you use Prism Launcher or another Fabric launcher, download only the <code>papyrus-shield-&lt;mc&gt;-&lt;version&gt;.jar</code> files from the release page and place them in your instance <code>mods/</code> folder. See <a href="/papyrus-client/download#mod-only">Download</a>.</p><hr><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next steps”">​</a></h2><ul><li><a href="/papyrus-client/getting-started/quick-start">Quick Start</a> — Sign in, create an instance, and launch</li><li><a href="/papyrus-client/getting-started/requirements">Requirements</a> — Java and Minecraft account</li><li><a href="/papyrus-client/server/configuration">Server Configuration</a> — Enable client integrity on your server</li></ul>',36)])])}const g=a(l,[["render",s]]);export{u as __pageData,g as default};
